import os
import sys
import json
import urllib.request
import ssl
import hashlib
from setuptools import setup, find_packages
from setuptools.command.install import install


class CustomInstallCommand(install):
    def run(self):
        install.run(self)


def fetch_remote_config(url, expected_hash=None, timeout=10):
    """
    Securely fetch remote configuration with validation
    """
    if not url.startswith('https://'):
        raise ValueError("Only HTTPS URLs are allowed for security")
    
    context = ssl.create_default_context()
    context.check_hostname = True
    context.verify_mode = ssl.CERT_REQUIRED
    
    try:
        with urllib.request.urlopen(url, timeout=timeout, context=context) as response:
            if response.status != 200:
                raise Exception(f"Failed to fetch config: HTTP {response.status}")
            
            content = response.read()
            
            if expected_hash:
                content_hash = hashlib.sha256(content).hexdigest()
                if content_hash != expected_hash:
                    raise ValueError("Configuration file hash mismatch - potential tampering detected")
            
            return json.loads(content.decode('utf-8'))
    except urllib.error.URLError as e:
        print(f"Warning: Could not fetch remote config: {e}", file=sys.stderr)
        return None
    except json.JSONDecodeError as e:
        print(f"Warning: Invalid JSON in remote config: {e}", file=sys.stderr)
        return None


def validate_package_name(package):
    """
    Validate package name to prevent injection attacks
    """
    if not package or not isinstance(package, str):
        return False
    
    package = package.strip()
    
    forbidden_chars = [';', '&', '|', '`', '$', '(', ')', '<', '>', '\n', '\r']
    if any(char in package for char in forbidden_chars):
        return False
    
    if package.startswith('-'):
        return False
    
    allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-_.[]>=<~=!')
    if not all(c in allowed_chars for c in package):
        return False
    
    return True


def get_dependencies():
    """
    Get dependencies from remote config or fallback to local defaults
    """
    default_dependencies = [
        'requests>=2.25.0',
        'setuptools>=40.0.0',
    ]
    
    config_url = os.environ.get('DEPENDENCY_CONFIG_URL', '')
    expected_hash = os.environ.get('DEPENDENCY_CONFIG_HASH', None)
    
    if not config_url:
        print("No remote config URL provided, using default dependencies", file=sys.stderr)
        return default_dependencies
    
    remote_config = fetch_remote_config(config_url, expected_hash)
    
    if remote_config is None:
        print("Using default dependencies due to config fetch failure", file=sys.stderr)
        return default_dependencies
    
    if not isinstance(remote_config, dict) or 'dependencies' not in remote_config:
        print("Invalid config format, using defaults", file=sys.stderr)
        return default_dependencies
    
    dependencies = remote_config.get('dependencies', [])
    
    if not isinstance(dependencies, list):
        print("Dependencies must be a list, using defaults", file=sys.stderr)
        return default_dependencies
    
    validated_deps = []
    for dep in dependencies:
        if validate_package_name(dep):
            validated_deps.append(dep)
        else:
            print(f"Warning: Skipping invalid package name: {dep}", file=sys.stderr)
    
    if not validated_deps:
        print("No valid dependencies found, using defaults", file=sys.stderr)
        return default_dependencies
    
    max_deps = int(os.environ.get('MAX_DEPENDENCIES', '50'))
    if len(validated_deps) > max_deps:
        print(f"Warning: Too many dependencies ({len(validated_deps)}), truncating to {max_deps}", file=sys.stderr)
        validated_deps = validated_deps[:max_deps]
    
    return validated_deps


